```{.r .cell-code}
acc_table <- acc_nums %>%
  filter(season != 2020) %>%
  gt() %>%
  cols_label(
    # rename columns
    season = "Year",
    team = "Team",
    ncaa_seed = "Seed",
    continuity = "% Min",
    experience = "Years",
    continuity_rk = "D-I Rank",
    experience_rk = "D-I Rank"
  ) %>%
  tab_spanner(label = "Continuity",
              columns = c(continuity, continuity_rk)) %>%
  tab_spanner(label = "Experience",
              columns = c(experience, experience_rk)) %>%
  gt_theme_dot_matrix() %>%
  tab_header(title = "Experience and Minutes Continuity for the Big Four") %>%
  tab_source_note(source_note = "@dadgumboxscores | March 15 | data via kenpom & hoopR") %>%
  tab_options (
    source_notes.font.size = px(10),
    row.striping.background_color = '#ffffed',
    table.font.size = px(10),
    column_labels.text_transform = 'capitalize'
  )

gtsave_extra(acc_table,
             "acc_table.png"
)

